import React, { useState, useEffect } from 'react';
import LoginScreen from './components/LoginScreen';
import AppAuthenticated from './AppAuthenticated';
import { useAppSecurity } from './hooks/useAppSecurity';
import { DataProvider, useData } from './context/DataContext';
import { SystemConfig, UserData, Task, DBItem, MapSector, PriorityLevel, InventorySession, Notification, PartRequest, BOMRequest, BreakSchedule, SystemBreak, BOMComponent, Role, Permission } from './types/appTypes';

// Export types for backward compatibility with components
export type { 
  UserData, Task, DBItem, MapSector, PriorityLevel, InventorySession,
  Notification, PartRequest, BOMRequest, BreakSchedule, SystemBreak,
  BOMComponent, Role, Permission, SystemConfig 
};

// --- INNER COMPONENT (Consumes Context) ---
const AppContent = ({ 
  isAuthenticated, 
  currentUser, 
  currentUserRole, 
  onLoginSuccess, 
  onLogout, 
  systemConfig, 
  isUnlocked, 
  onUnlockAttempt, 
  onUpdateAdminKey, 
  onToggleAdminLock, 
  onUpdateSystemConfig, 
  installPrompt, 
  onInstallApp 
}: any) => {
  const { users } = useData(); 
  const [unlockKey, setUnlockKey] = useState("");

  // SERVICE MODE WATCHER: Okamžité vyhodenie ne-adminov pri zapnutí údržby
  useEffect(() => {
    if (isAuthenticated && currentUserRole !== 'ADMIN') {
      const now = new Date();
      const currentISO = new Date(now.getTime() - (now.getTimezoneOffset() * 60000)).toISOString().slice(0, 16);
      const isScheduled = systemConfig.maintenanceStart && systemConfig.maintenanceEnd && 
                         currentISO >= systemConfig.maintenanceStart && 
                         currentISO <= systemConfig.maintenanceEnd;

      if (systemConfig.maintenanceMode || isScheduled) {
        onLogout();
      }
    }
  }, [systemConfig.maintenanceMode, systemConfig.maintenanceStart, systemConfig.maintenanceEnd, isAuthenticated, currentUserRole, onLogout]);

  if (!isAuthenticated) {
    return (
      <LoginScreen 
        onLoginSuccess={onLoginSuccess} 
        users={users} 
        systemConfig={systemConfig} 
      />
    );
  }

  // Admin Lock Screen
  if (currentUserRole === 'ADMIN' && systemConfig.adminLockEnabled && !isUnlocked) {
    return (
        <div className="flex flex-col items-center justify-center p-10 bg-gray-900 w-full h-full">
            <div className="flex flex-col items-center justify-center p-10 bg-gray-900 rounded-2xl border-2 border-amber-600 shadow-2xl">
