                    onKeyDown={(e) => e.key === 'Enter' && onUnlockAttempt(unlockKey)}
                />
                <button 
                    onClick={() => onUnlockAttempt(unlockKey)}
                    className="w-full py-3 bg-amber-600 hover:bg-amber-500 text-white rounded-xl font-black transition-all"
                >
